"""Guild-level deficit computation engine per EC-03."""

import json

from guild_ops.storage.database import Database


def compute_deficits(db: Database, contract_id: str) -> list[dict]:
    """Compute guild-level deficits for a contract. Returns deficit list."""
    contract_row = db.get_contract(contract_id)
    if not contract_row:
        raise ValueError(f"Contract {contract_id} not found")

    contract_data = contract_row["data"]
    roster = contract_data.get("roster", {}).get("entries", [])
    role_requirements = contract_data.get("role_requirements", {})
    guild_materials = contract_data.get("guild_materials", [])

    # Compute total required per item
    required: dict[int, dict] = {}  # item_id -> {name, total_required}

    for entry in roster:
        role = entry.get("assigned_role")
        role_req = role_requirements.get(role, {})

        for consumable in role_req.get("required_consumables", []):
            iid = consumable["item_id"]
            qty = consumable.get("quantity", 1)
            if iid not in required:
                required[iid] = {
                    "item_id": iid,
                    "item_name": consumable.get("item_name", f"Item #{iid}"),
                    "total_required": 0,
                }
            required[iid]["total_required"] += qty

        for consumable in role_req.get("optional_consumables", []):
            iid = consumable["item_id"]
            qty = consumable.get("quantity", 1)
            if iid not in required:
                required[iid] = {
                    "item_id": iid,
                    "item_name": consumable.get("item_name", f"Item #{iid}"),
                    "total_required": 0,
                }
            required[iid]["total_required"] += qty

    # Add guild-level material requirements
    for mat in guild_materials:
        iid = mat["item_id"]
        if iid not in required:
            required[iid] = {
                "item_id": iid,
                "item_name": mat.get("item_name", f"Item #{iid}"),
                "total_required": 0,
            }
        required[iid]["total_required"] += mat.get("total_quantity", 0)

    # Compute total available per item (player inventories + guild bank)
    available: dict[int, int] = {}

    # Player inventories
    for entry in roster:
        char_id = entry.get("character_id", "")
        char_row = db.get_character(char_id)
        if not char_row:
            continue
        char_data = char_row.get("data", {})
        inv = char_data.get("inventory_consumables")
        if not inv:
            continue
        for inv_item in inv:
            iid = inv_item.get("item_id")
            qty = inv_item.get("quantity", 0)
            if iid:
                available[iid] = available.get(iid, 0) + qty

    # Guild bank
    for bank_item in db.get_guild_bank():
        iid = bank_item["item_id"]
        qty = bank_item["quantity"]
        available[iid] = available.get(iid, 0) + qty

    # Build deficit list
    deficits: list[dict] = []
    for iid, info in sorted(required.items()):
        total_req = info["total_required"]
        total_avail = available.get(iid, 0)
        deficit_qty = max(0, total_req - total_avail)
        deficits.append({
            "item_id": iid,
            "item_name": info["item_name"],
            "total_required": total_req,
            "total_available": total_avail,
            "deficit_quantity": deficit_qty,
        })

    return deficits

