"""Output formatting utilities per RC-04."""

import json
from typing import Any

from guild_ops.config import AppConfig
from guild_ops.models import ReadinessStatus, TrendDirection
from guild_ops.models.evaluation import EconomicRecommendation, ReadinessClassification


def format_gold(copper: int) -> str:
    """Format copper amount as gold/silver/copper display."""
    if copper <= 0:
        return "0g"
    gold = copper // 10000
    silver = (copper % 10000) // 100
    copper_rem = copper % 100
    parts = []
    if gold > 0:
        parts.append(f"{gold}g")
    if silver > 0:
        parts.append(f"{silver}s")
    if copper_rem > 0:
        parts.append(f"{copper_rem}c")
    return " ".join(parts) if parts else "0g"


def trend_indicator(direction: TrendDirection | str) -> str:
    """Return text trend indicator."""
    d = direction if isinstance(direction, str) else direction.value
    if d == "RISING":
        return "RISING"
    elif d == "FALLING":
        return "FALLING"
    return "STABLE"


def format_deficits(deficits: list[dict], fmt: str = "text") -> str:
    """Format deficit list for output."""
    if fmt == "json":
        return json.dumps(deficits, indent=2, sort_keys=True, default=str)

    if not deficits:
        return "No deficits found."

    lines = ["=== Guild Deficit Report ===", ""]
    lines.append(f"{'Item':<35} {'Required':>10} {'Available':>10} {'Deficit':>10}")
    lines.append("-" * 70)
    for d in deficits:
        lines.append(
            f"{d['item_name']:<35} {d['total_required']:>10} "
            f"{d['total_available']:>10} {d['deficit_quantity']:>10}"
        )
    total_deficit = sum(d["deficit_quantity"] for d in deficits)
    lines.append("-" * 70)
    lines.append(f"{'Total deficit items':<35} {'':>10} {'':>10} {total_deficit:>10}")
    return "\n".join(lines)


def format_recommendations(
    recommendations: list[EconomicRecommendation],
    config: AppConfig,
    fmt: str = "text",
) -> str:
    """Format economic recommendations for output per RC-03."""
    if fmt == "json":
        data = [r.model_dump(mode="json") for r in recommendations]
        return json.dumps(data, indent=2, sort_keys=True, default=str)

    if not recommendations:
        return "No economic recommendations."

    lines = [
        "=== Economic Detail Report ===",
        "",
        f"Thresholds: BUY <= {config.economic_thresholds.buy_threshold:.0%} of avg | "
        f"WAIT >= {config.economic_thresholds.wait_threshold:.0%} of avg",
        "",
    ]

    total_cost = sum(r.estimated_cost_copper for r in recommendations)
    deficit_count = sum(1 for r in recommendations if r.deficit_quantity > 0)
    lines.append(f"Total deficit items: {deficit_count}")
    lines.append(f"Total estimated cost: {format_gold(total_cost)}")
    lines.append("")
    lines.append(
        f"{'Item':<30} {'Deficit':>7} {'Price':>12} {'Avg':>12} "
        f"{'Trend':>8} {'Action':>6} {'Conf':>6} {'Est Cost':>12}"
    )
    lines.append("-" * 100)

    for r in recommendations:
        trend_str = trend_indicator(r.confidence.value if hasattr(r, '_trend_direction') else "STABLE")
        # We don't have trend_direction on the recommendation directly,
        # so we infer from the reason text
        if "rising" in r.reason.lower():
            trend_str = "RISING"
        elif "below" in r.reason.lower() or "falling" in r.reason.lower():
            trend_str = "FALLING"
        else:
            trend_str = "STABLE"

        lines.append(
            f"{r.item_name:<30} {r.deficit_quantity:>7} "
            f"{format_gold(r.current_price_copper):>12} "
            f"{format_gold(r.average_price_copper):>12} "
            f"{trend_str:>8} {r.action.value:>6} "
            f"{r.confidence.value:>6} {format_gold(r.estimated_cost_copper):>12}"
        )

    return "\n".join(lines)


def format_readiness(
    classifications: list[ReadinessClassification],
    fmt: str = "text",
) -> str:
    """Format readiness classifications for output."""
    if fmt == "json":
        data = [c.model_dump(mode="json") for c in classifications]
        return json.dumps(data, indent=2, sort_keys=True, default=str)

    if not classifications:
        return "No readiness data."

    lines = ["=== Player Readiness Report ===", ""]
    ready = sum(1 for c in classifications if c.status == ReadinessStatus.READY)
    warning = sum(1 for c in classifications if c.status == ReadinessStatus.WARNING)
    not_ready = sum(1 for c in classifications if c.status == ReadinessStatus.NOT_READY)
    total = len(classifications)

    lines.append(f"READY: {ready}/{total}  WARNING: {warning}/{total}  NOT_READY: {not_ready}/{total}")
    lines.append("")

    for c in classifications:
        status_marker = {"READY": "[OK]", "WARNING": "[!!]", "NOT_READY": "[XX]"}
        lines.append(f"  {status_marker.get(c.status.value, '[??]')} {c.character_id} — {c.status.value}")
        for v in c.violations:
            sev = "MANDATORY" if v.severity.value == "MANDATORY" else "advisory"
            lines.append(f"      [{sev}] {v.description}")
            lines.append(f"               Remedy: {v.remediation}")
            if v.market_info:
                lines.append(f"               Market: {v.market_info}")

    return "\n".join(lines)


def format_drift(events: list, fmt: str = "text") -> str:
    """Format drift events for output."""
    if fmt == "json":
        data = [e.model_dump(mode="json") if hasattr(e, 'model_dump') else e for e in events]
        return json.dumps(data, indent=2, sort_keys=True, default=str)

    if not events:
        return "No drift detected."

    lines = ["=== Drift Detection Report ===", ""]
    for e in events:
        if hasattr(e, 'drift_type'):
            lines.append(f"  [{e.drift_type.value}] {e.subject}")
            lines.append(f"    Previous: {e.previous_state}")
            lines.append(f"    Current:  {e.current_state}")
            lines.append(f"    Impact:   {e.impact}")
            lines.append(f"    Action:   {e.recommended_action}")
            lines.append("")
    return "\n".join(lines)

